// --- sensor.h ---
// Standard Preprocessor Guards prevent multiple definitions if this file
// is included twice by different modules.
#ifndef SENSOR_H
#define SENSOR_H

// Alternatively, #pragma once is widely supported by GCC/Clang/MSVC
// and executes significantly faster because the compiler doesn't even open the file twice.

struct SensorData {
    int temp;
    int pressure;
};

#endif // SENSOR_H

#include &lt;stdio.h&gt;

// The Preprocessor determines which block of text survives based on compiler flags.
void clear_screen() {
#ifdef _WIN32
    // Windows-specific compiler flag detected
    system("cls");
#elif defined(__linux__)
    // Linux-specific compiler flag detected
    system("clear");
#else
    #error "Unsupported OS Platform!"
#endif
}

// --- custom_math.h ---
