#include &lt;stdio.h&gt;

// 1. Unsafe Macro (Missing Parentheses)
#define UNSAFE_MUL(a, b) a * b

// 2. Safe Expression Macro (Wrapped to the extreme)
#define SAFE_MUL(a, b) ((a) * (b))

// 3. Multi-line Logic Macro
// Using do-while(0) forces the macro to act as a single, safely-terminated block.
#define LOG_ERROR(msg) do { \
    fprintf(stderr, "ERROR: "); \
    fprintf(stderr, "%s\n", (msg)); \
} while(0)

int main() {
    // If LOG_ERROR wasn't wrapped in do-while(0), the second fprintf
    // would execute unconditionally outside this 'if' statement!
    if (1 == 0)
        LOG_ERROR("This will not print.");

    return 0;
}

#include &lt;stdio.h&gt;

// The # operator takes the raw text of the argument and puts quotes around it.
#define PRINT_VAR_NAME(var) printf("Variable '" #var "' = %d\n", var)

int main() {
    int threshold = 500;
    int velocity = 200;

    // The preprocessor expands this to:
    // printf("Variable '" "threshold" "' = %d\n", threshold);
    PRINT_VAR_NAME(threshold); // Output: Variable 'threshold' = 500
    PRINT_VAR_NAME(velocity);  // Output: Variable 'velocity' = 200

    return 0;
}

#include &lt;stdio.h&gt;

// The ## operator fuses two tokens together to create a NEW variable name or function.
#define DECLARE_VAR(name, val) int engine_##name = val

int main() {
    // The preprocessor expands this directly to: int engine_speed = 300;
    DECLARE_VAR(speed, 300);
    DECLARE_VAR(temp, 95);

    printf("Speed: %d, Temp: %d\n", engine_speed, engine_temp);
    return 0;
}

#include &lt;stdio.h&gt;

// A macro to safely swap two variables using a temporary holder
#define SWAP(a, b) do { \
    int temp = a; \
    a = b; \
    b = temp; \
} while(0)

int main() {
    int temp = 5;
    int val = 10;

    // DANGER: The caller happens to use the exact same variable name ('temp')
    // as the internal macro logic.
    SWAP(temp, val);

    printf("Temp: %d, Val: %d\n", temp, val);
    return 0;
}

#include &lt;stdio.h&gt;

// A robust logging macro injecting file and line numbers automatically.
// The ##__VA_ARGS__ is a GCC extension that deletes the preceding comma 
// if no extra arguments are passed, preventing syntax errors.
#define LOG_INFO(fmt, ...) do { \
    printf("[INFO] %s:%d: ", __FILE__, __LINE__); \
    printf(fmt, ##__VA_ARGS__); \
    printf("\n"); \
} while(0)

int main() {
    // Handles arbitrary argument counts dynamically
    LOG_INFO("Boot sequence initiated.");
    LOG_INFO("User %d authenticated from IP %s", 42, "192.168.1.1");
    return 0;
}

#include &lt;stdio.h&gt;

// 1. The Master List (The Single Source of Truth)
#define ERROR_CODES \
    X(ERR_OK, "Success") \
    X(ERR_MEM, "Out of Memory") \
    X(ERR_NET, "Network Timeout")

// 2. Generate the ENUM
// We redefine what 'X' means to extract only the name
#define X(name, msg) name,
typedef enum {
    ERROR_CODES
} ErrorCode;
#undef X // ALWAYS clean up the macro immediately

// 3. Generate the String Array
// We redefine 'X' to extract the string message
#define X(name, msg) msg,
const char *ErrorStrings[] = {
    ERROR_CODES
};
#undef X

int main() {
    ErrorCode code = ERR_NET;
    // The enum and strings are perfectly synchronized forever.
    printf("Code %d means: %s\n", code, ErrorStrings[code]);
    return 0;
}

